SELECT EXISTS(
    SELECT 1
    FROM skill_turn_snapshot
    WHERE session_id = #{sessionId}
      AND turn_id = #{turnId}
      AND seq = #{seq}
)

SELECT tenant_id, client_id, session_id, turn_id, seq, trace_id, actor, event_type, payload, turn_status, delivery_status, created_at FROM skill_turn_snapshot WHERE tenant_id = #{tenantId} AND client_id = #{clientId} AND session_id = #{sessionId}
AND turn_id > #{cursorTurnId}
ORDER BY created_at ASC, turn_id ASC LIMIT #{limit}

SELECT EXISTS(
    SELECT 1
    FROM skill_turn_snapshot
    WHERE tenant_id = #{tenantId}
      AND client_id = #{clientId}
      AND session_id = #{sessionId}
)

